SELECT description
FROM building_materials
WHERE material_id = 1;

SELECT leed_category
FROM leed_certifications
WHERE material_id = 1;

SELECT material_type, manufacturer
FROM building_materials
WHERE material_category = 'roofing';

SELECT COUNT(*) AS material_count
FROM building_materials
WHERE material_category = 'Roofing';

SELECT material_id, material_type
FROM building_materials
ORDER BY material_type;

SELECT warranty_id, material_id, warranty_period, file_path
FROM warranty_documents
WHERE warranty_period = '10 years';

SELECT project_name
FROM projects
ORDER BY project_name ASC;

SELECT COUNT(*) AS total_materials_supplied
FROM material_supplies
WHERE supplier_id = 0;

SELECT MAX(quantity) AS max_quantity
FROM project_materials
WHERE project_id = 1;

SELECT DISTINCT p.project_name AS "Project Name"
FROM projects p
JOIN project_materials pm ON p.project_id = pm.project_id;
